var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"멀린 제사장은 들으시오!","JPN":"マーリン祭祀長、聞いてくれ！","ENG":"Listen here, High Priest Merlin!","TWN":"梅林祭司長，聽著！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"지금 당장 반역자를 넘기지 않으면, 당신부터 그 자리에서 끌어내겠소!","JPN":"今すぐ反逆者を渡さないと、あなたをここから追い出す！","ENG":"If you don't hand over the traitor to us, we will drag you down from your position!","TWN":"如果你現在不交出叛徒，就先把你從那位置上拉下來！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 얘긴 이미 끝났다고 생각했는데.","JPN":"その話はもう終わったと思っていたけど。","ENG":"I believe this conversation was already concluded.","TWN":"我以為那件事已經到此為止了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이를 데려가서 어쩔 셈이지?","JPN":"あの子を連れて行ってどうするつもりかしら。","ENG":"What are you going to do to the child?","TWN":"你打算帶走那個孩子做什麼？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"처단하는 거요! 그루터기와 세계의 안위를 위해서!","JPN":"始末する！　切り株と世界の安危のために！","ENG":"Execute her! This is for the good of the Stump and the world!","TWN":"處決她！為了木墩和世界的安全！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"단 한 명의 희생으로 다른 수많은 목숨을 구한다라…","JPN":"一人の犠牲で他の多くの命を救う、ねえ……","ENG":"Sacrificing one to save the lives of others...","TWN":"用一個人的犧牲來拯救其他無數的生命…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"참 손쉽고 명료해 보이는 해결책이네.","JPN":"とても単純明快な解決策だわ。","ENG":"What a simple and easy resolution you have come up with.","TWN":"真是看起來簡單粗暴的解方呢。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 뒤에 있는 사람들도, 모두 그 의견에 찬동해서 온 건가?","JPN":"その後ろにいる人たちも、みんなその意見に同意して来たの？","ENG":"And the people behind you, are they all here in agreement with your views?","TWN":"那些人也都同意這個提議嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"예언은 틀린 적이 없어요! 그 여잘 내버려두면 악마를 끌어들여서 우릴 모두 죽일 거라고요!","JPN":"今まで予言は外れたことがありません！　あの女を放っておけば、悪魔を引き連れみんな殺されてしまう！","ENG":"The prophecies have never been wrong! If we let that girl live, she'll bring in the devil and kill us all!","TWN":"預言哪次出過錯！如果放任那個女孩不管，她會引來魔鬼殺死我們所有人！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그루터기는 예언을 믿고 따르라 가르쳤잖습니까!","JPN":"切り株は予言を信じ、従うよう教えてきたではありませんか！","ENG":"You've taught us to believe and follow the prophecies!","TWN":"木墩教導我們要相信並遵循預言！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"악마와 엮일 게 분명한 인간을 두고만 보다니, 납득할 수 없어요!","JPN":"悪魔と関係のある人間をこのまま見過ごすなんて、納得できません！","ENG":"Yet, I don't understand how you can let this girl who is clearly involved with the devil be here!","TWN":"為什麼你還會允許一個明顯與魔鬼有糾纏的人在這裡？我無法接受！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"우리 목적을 이루려면, 그루터기엔 한 명이라도 더 많은 성자가 필요해.","JPN":"アタシたちの目的を果たすためには、切り株に一人でも多くの聖者が必要だわ。","ENG":"In order to achieve our goal, the Stump needs as many Helgons as we can find.","TWN":"為了實現我們的目標，木墩需要更多的聖者。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"얼마 전 낙원을 관측했으니, 낙원문 기술을 좀 더 발전시키기만 하면 우리 모두가 함께 예견된 종말을 피할 수 있어.","JPN":"この前楽園を観測したから、楽園の門の技術をもう少し発展させればアタシたちみんな予言された終末を回避できるの。","ENG":"Recently, I have observed the Promised Land, and with improvements to our technology, we will be able to avoid the prophesized doom.","TWN":"不久前我們已經觀測到了樂園，只要進一步發展樂園門技術，我們所有人都能一起避開預言中的末日。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러니 조급해말고…","JPN":"だから、焦らずに……","ENG":"So, be patient and–","TWN":"所以不要急…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"낙원문은 아발론의 선조들조차 수백 년간 완성하지 못한 장치지.","JPN":"楽園の門はアバロンの祖先さえ数百年間完成できなかった装置だ。","ENG":"Avalon's Gate is something that not even the ancestors of Avalon could complete.","TWN":"樂園門是阿瓦隆的祖先們幾百年都未能完成的裝置！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"단 한 명의 인간조차 낙원으로 인도하지 못하는 그 커다란 고철덩이는 기약 없는 희망이자 당장의 비참한 현실에서 눈 돌리기 위한 수단일 뿐이오!","JPN":"たった一人の人間すら楽園に導くことのできないあのデカい鉄の塊は、限りない希望であると同時に現在の惨めな現実から目を背けるための手段にすぎない！","ENG":"It has never guided a single person to the Promised Land and is a giant piece of scrap metal using hope as a diversion to get the people's attention away from their miserable reality!","TWN":"那不過是連一個人都無法引導到樂園的巨大廢鐵，一個無望的希望，一個為了逃避眼前悲慘現實而自我欺騙的手段而已！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"何……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그 낙원문에 쓸 적철을 구하기 위해, 제 조부님과 아버지께선 조사단원으로서 목숨을 바치셨어요!","JPN":"その楽園の門に使う赤鉄を探すため、私の祖父と父は調査団員として命を捧げたんです！","ENG":"My father and his father sacrificed their lives as members of the survey corps to find Violarite for Avalon's Gate!","TWN":"為了獲取建造門所需的赤鐵，我的祖父和父親作為調查團員都獻出了生命！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그런데 어째서 한 사람의 목숨에는 그토록 집요하신 겁니까!","JPN":"なのに、どうしてたった一人の命にそこまで固執するのですか！","ENG":"Yet, why are you so obsessed about this one girl's life?!","TWN":"為什麼你要對這個女孩的生命如此執著！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"맞아요! 평생을 그루터기에 숨어 명령만 내려왔으면서 당신만 옳다는 고집은 버리라고요!","JPN":"そうです！　ずっと切り株に隠れて命令していただけのあなたが、正義を主張しないでください！","ENG":"He's right! You've spent your entire life hiding in the Stump and ordering us around! It's time that you learned that your decisions aren't the only ones that are right!","TWN":"沒錯！你一生都只躲在木墩裡發號施令，放棄你那自以為是的固執吧！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희들……","JPN":"アナタたち……","ENG":"You...","TWN":"你們…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그만둬요!","JPN":"やめて！","ENG":"ENOUGH!","TWN":"住手！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"죄도 없는 사람을 몰아가려고 이렇게 많이 모이다니! 다 큰 어른들이 부끄럽지도 않아요?!","JPN":"罪のない人を追いやるためにこんなに大勢集まるなんて！　大人たちが恥ずかしくないんですか！？","ENG":"Aren't you all ashamed of yourselves?! Gathering like this to banish an innocent person?!","TWN":"為了逼迫一個無辜者竟然聚集了這麼多人！你們這些大人不覺得羞恥嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"카롤리스…?","JPN":"カロリス……？","ENG":"Karolis...?","TWN":"卡羅黎斯…？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"돌아가. 네가 상관할 일이 아니다.","JPN":"帰れ。お前には関係ない。","ENG":"Go home. This is none of your concern!","TWN":"回去吧，這與你無關。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};